226:   void stopListeners(StopListenersType stop_listeners_type,
227:                      const Network::ExtraShutdownListenerOptions& options) override;
228:   void stopWorkers() override;
229:   void beginListenerUpdate() override { error_state_tracker_.clear(); }
230:   void endListenerUpdate(FailureStates&& failure_state) override;
231:   bool isWorkerStarted() override { return workers_started_; }
232:   Http::Context& httpContext() { return server_.httpContext(); }
233:   ApiListenerOptRef apiListener() override;
