243:    * Callback invoked when a listener initialization is completed on worker.
244:    */
245:   using ListenerCompletionCallback = std::function<void()>;
246: 
247:   bool addOrUpdateListenerInternal(const envoy::config::listener::v3::Listener& config,
248:                                    const std::string& version_info, bool added_via_api,
249:                                    const std::string& name);
250:   bool removeListenerInternal(const std::string& listener_name, bool dynamic_listeners_only);
251: 
252:   struct DrainingListener {
253:     DrainingListener(ListenerImplPtr&& listener, uint64_t workers_pending_removal)
254:         : listener_(std::move(listener)), workers_pending_removal_(workers_pending_removal) {}
255: 
256:     ListenerImplPtr listener_;
257:     uint64_t workers_pending_removal_;
258:   };
259: 
260:   bool doFinalPreWorkerListenerInit(ListenerImpl& listener);
